+            AgentType::Unknown
+        ));
+
+        // WezTerm rules should apply to all agents
+        let wezterm_detection = Detection {
+            rule_id: "wezterm.pane_exited".into(),
+            agent_type: AgentType::Wezterm,
+            event_type: "lifecycle".into(),
